#include <stdio.h>
#include <math.h>
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int X[N], Y[N], R[N];
    for (int i = 0; i < N; i++) {
        scanf("%d %d %d", &X[i], &Y[i], &R[i]);
    }
    for (int q = 0; q < Q; q++) {
        int K;
        scanf("%d", &K);
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                double distance = sqrt(pow(X[i] - X[j], 2) + pow(Y[i] - Y[j], 2));
                if (distance <= R[i] + R[j] + K || distance >= abs(R[i] - R[j]) + K) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

