import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int Q = scanner.nextInt();
        int[] X = new int[N];
        int[] Y = new int[N];
        int[] R = new int[N];
        for (int i = 0; i < N; i++) {
            X[i] = scanner.nextInt();
            Y[i] = scanner.nextInt();
            R[i] = scanner.nextInt();
        }
        for (int q = 0; q < Q; q++) {
            int K = scanner.nextInt();
            int count = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    double distance = Math.sqrt(Math.pow(X[i] - X[j], 2) + Math.pow(Y[i] - Y[j], 2));
                    if (distance <= R[i] + R[j] + K || distance >= Math.abs(R[i] - R[j]) + K) {
                        count++;
                    }
                }
            }
            System.out.println(count);
        }
    }
}

