const readline = () => lines[idx++];
const N = parseInt(readline().split(' ')[0]);
const Q = parseInt(readline().split(' ')[1]);
const X = [];
const Y = [];
const R = [];
for (let i = 0; i < N; i++) {
    const [x, y, r] = readline().split(' ').map(Number);
    X.push(x);
    Y.push(y);
    R.push(r);
}
for (let q = 0; q < Q; q++) {
    const K = parseInt(readline());
    let count = 0;
    for (let i = 0; i < N; i++) {
        for (let j = i + 1; j < N; j++) {
            const distance = Math.sqrt(Math.pow(X[i] - X[j], 2) + Math.pow(Y[i] - Y[j], 2));
            if (distance <= R[i] + R[j] + K || distance >= Math.abs(R[i] - R[j]) + K) {
                count++;
            }
        }
    }
    console.log(count);
}

